{
  "live-restore": true,
  "log-driver": "json-file",
  "log-opts": {
    "max-size": "100m",
    "max-file": "3"
  }
}

BACKUP_DAILY_RETENTION_DAYS={{ backup_daily_retention_days | default(14) }}
BACKUP_MONTHLY_RETENTION_MONTHS={{ backup_monthly_retention_months | default(6) }}
BACKUP_MIN_RESTORE_POINTS={{ backup_min_restore_points | default(3) }}
BACKUP_ENCRYPTION_REQUIRED=true

{{ platform_log_path }} {
  daily
  rotate {{ platform_log_rotate_count | default(14) }}
  compress
  missingok
  notifempty
}

Unattended-Upgrade::Allowed-Origins {
  "${distro_id}:${distro_codename}-security";
};
Unattended-Upgrade::Automatic-Reboot "{{ unattended_reboot | default('false') }}";
Unattended-Upgrade::Automatic-Reboot-Time "{{ unattended_reboot_time | default('03:30') }}";

Environment: {{ environment_name | default('unknown') }}
Owner: {{ platform_owner | default('platform') }}
Support: {{ support_contact | default('unset') }}
Do not paste secrets into shell history or tickets.

PermitRootLogin no
PasswordAuthentication {{ ssh_password_authentication | default('no') }}
AllowUsers {% for user in ssh_allowed_users | default([]) %}{{ user }}{% if not loop.last %} {% endif %}{% endfor %}

[Journal]
Storage=persistent
Compress=yes
SystemMaxUse={{ journald_system_max_use | default('1G') }}
MaxRetentionSec={{ journald_max_retention_sec | default('14day') }}

[Service]
Restart=on-failure
RestartSec={{ service_restart_seconds | default(5) }}

[Unit]
StartLimitIntervalSec={{ service_start_limit_interval_seconds | default(300) }}
StartLimitBurst={{ service_start_limit_burst | default(5) }}

[Service]
MemoryMax={{ service_memory_max | default('1G') }}
LimitNOFILE={{ service_limit_nofile | default(65536) }}
TasksMax={{ service_tasks_max | default(512) }}

{
  "backup_id": {{ restore_drill_backup_id | to_json }},
  "checksum_verified": {{ restore_drill_checksum_verified | bool | lower }},
  "started_at": {{ restore_drill_started_at | to_json }},
  "completed_at": {{ restore_drill_completed_at | to_json }},
  "application_verification_passed": {{ restore_drill_application_verification_passed | bool | lower }}
}

import unittest
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


class RestoreDrillEvidenceTemplateTests(unittest.TestCase):
    def test_template_records_integrity_timing_and_application_checks(self):
        content = (ROOT / "roles/backup/templates/restore-drill-evidence.json.j2").read_text(encoding="utf-8")

        for field in ("backup_id", "checksum_verified", "started_at", "completed_at", "application_verification_passed"):
            self.assertIn(f'"{field}"', content)

    def test_template_does_not_embed_secret_fields(self):
        content = (ROOT / "roles/backup/templates/restore-drill-evidence.json.j2").read_text(encoding="utf-8").lower()
        self.assertNotIn("password", content)
        self.assertNotIn("private_key", content)


if __name__ == "__main__":
    unittest.main()
